import{_ as t,o,c as d,au as a}from"./chunks/framework.Bpqx6pAq.js";const u=JSON.parse('{"title":"Features hooks","description":"","frontmatter":{},"headers":[],"relativePath":"api/map/hooks/hooks.features.md","filePath":"api/map/hooks/hooks.features.md"}'),r={name:"api/map/hooks/hooks.features.md"};function s(i,e,c,n,l,h){return o(),d("div",null,[...e[0]||(e[0]=[a('<h1 id="features-hooks" tabindex="-1">Features hooks <a class="header-anchor" href="#features-hooks" aria-label="Permalink to &quot;Features hooks&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Hooks for the features service: controlling result size on bulk operations, suppressing or simplifying real-time events for multi-feature mutations, and enabling fuzzy text search on feature label properties.</p><h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h2><h3 id="simplifyresult-hook" tabindex="-1"><code>simplifyResult(hook)</code> <a class="header-anchor" href="#simplifyresult-hook" aria-label="Permalink to &quot;`simplifyResult(hook)`&quot;">​</a></h3><blockquote><p>To be used as an <code>after</code> hook.</p></blockquote><p>Replaces the full result array with an array of <code>{ _id }</code> objects on bulk <code>create</code>, <code>update</code>, <code>patch</code>, and <code>remove</code> operations when the result exceeds a size threshold. This avoids sending large payloads to clients that only need the IDs.</p><p>Controlled by service options:</p><table tabindex="0"><thead><tr><th>Service option</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>simplifyResult</code></td><td><code>[&#39;create&#39;, &#39;update&#39;, &#39;patch&#39;, &#39;remove&#39;]</code></td><td>Methods for which simplification applies</td></tr><tr><td><code>simplifyResultLimit</code></td><td><code>1</code></td><td>Minimum result array length before simplification kicks in</td></tr></tbody></table><p>Override per-request by setting <code>hook.params.fullResult = true</code> to force the full result to be returned regardless of service options.</p><hr><h3 id="skipevents-hook" tabindex="-1"><code>skipEvents(hook)</code> <a class="header-anchor" href="#skipevents-hook" aria-label="Permalink to &quot;`skipEvents(hook)`&quot;">​</a></h3><blockquote><p>To be used as an <code>after</code> hook.</p></blockquote><p>Suppresses standard Feathers real-time events (<code>created</code>, <code>updated</code>, <code>patched</code>, <code>removed</code>) for bulk operations that exceed a size threshold, preventing the server from broadcasting large payloads to all clients.</p><p>Controlled by service options:</p><table tabindex="0"><thead><tr><th>Service option</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>skipEvents</code></td><td><code>[&#39;created&#39;, &#39;updated&#39;, &#39;patched&#39;, &#39;removed&#39;]</code></td><td>Events to suppress on bulk operations</td></tr><tr><td><code>simplifyEvents</code></td><td><code>[]</code></td><td>Events for which a simplified summary event is emitted instead (suppresses the raw event too)</td></tr><tr><td><code>skipEventsLimit</code></td><td><code>1</code></td><td>Minimum result array length before suppression kicks in</td></tr></tbody></table><p>Override per-request by setting <code>hook.params.emitEvents = true</code> to force normal event emission.</p><hr><h3 id="simplifyevents-hook" tabindex="-1"><code>simplifyEvents(hook)</code> <a class="header-anchor" href="#simplifyevents-hook" aria-label="Permalink to &quot;`simplifyEvents(hook)`&quot;">​</a></h3><blockquote><p>To be used as an <code>after</code> hook.</p></blockquote><p>Emits a lightweight summary event in place of the full per-item events for bulk operations listed in <code>service.options.simplifyEvents</code>. The summary payload includes:</p><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td><code>query</code></td><td>The query selector used for the bulk operation</td></tr><tr><td><code>total</code></td><td>Number of affected features</td></tr><tr><td><code>bbox</code></td><td>Bounding box <code>[west, south, east, north]</code> of all affected features</td></tr><tr><td><code>layers</code></td><td>Unique list of layer identifiers referenced by the affected features</td></tr><tr><td><code>startTime</code> / <code>endTime</code></td><td>UTC time range spanned by the affected features</td></tr><tr><td><code>data</code></td><td>Original patch/update data (not included for <code>created</code> events)</td></tr></tbody></table><p>Controlled by service options:</p><table tabindex="0"><thead><tr><th>Service option</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>simplifyEvents</code></td><td><code>[]</code></td><td>Events to replace with a summary payload</td></tr><tr><td><code>simplifyEventsLimit</code></td><td><code>1</code></td><td>Minimum result array length before simplification kicks in</td></tr></tbody></table><p>Override per-request by setting <code>hook.params.emitEvents = true</code> to force normal event emission.</p><hr><h3 id="fuzzysearch-hook" tabindex="-1"><code>fuzzySearch(hook)</code> <a class="header-anchor" href="#fuzzysearch-hook" aria-label="Permalink to &quot;`fuzzySearch(hook)`&quot;">​</a></h3><blockquote><p>To be used as a <code>before find</code> hook.</p></blockquote><p>Enables fuzzy text search on feature label properties. Reads the <code>featureLabel</code> option from the service configuration, prefixes each label field with <code>&#39;properties.&#39;</code>, and delegates to <code>feathers-mongodb-fuzzy-search</code>. No-op when no <code>featureLabel</code> is configured on the service.</p>',29)])])}const f=t(r,[["render",s]]);export{u as __pageData,f as default};
